import { cn } from '@/lib/utils';
import { sanitizeHtml } from '@/lib/sanitize-html';

// ─── Types ────────────────────────────────────────────────────────────────────

export type ButtonVariant = 'default' | 'secondary' | 'outline' | 'ghost' | 'link' | 'destructive';
export type ButtonSize = 'default' | 'sm' | 'lg' | 'icon' | 'icon-sm' | 'icon-lg';

export type ButtonOptions = {
  variant?: ButtonVariant;
  size?: ButtonSize;
  label?: string;
  ariaLabel?: string;
  ariaBusy?: boolean;
  ariaInvalid?: boolean;
  disabled?: boolean;
  type?: 'button' | 'submit' | 'reset';
  onClick?: (e: MouseEvent) => void;
  class?: string;
  children?: HTMLElement | string;
};

// ─── btnClass ─────────────────────────────────────────────────────────────────
//
// Retorna a lista de classes .mbds-button-* aplicáveis. Sempre inclui .mbds-button
// (base) + variante + (opcional) modificador de tamanho/ícone.
//
// Exemplos:
//   btnClass('default', 'default')  → 'mbds-button mbds-button-default'
//   btnClass('outline', 'sm')       → 'mbds-button mbds-button-sm mbds-button-outline'
//   btnClass('ghost',   'icon-lg')  → 'mbds-button mbds-button-icon-lg mbds-button-ghost'

export function btnClass(variant: ButtonVariant | string = 'default', size: ButtonSize | string = 'default'): string {
  const base = 'mbds-button';
  const sizeClass =
    size === 'icon'    ? 'mbds-button-icon' :
    size === 'icon-sm' ? 'mbds-button-icon-sm' :
    size === 'icon-lg' ? 'mbds-button-icon-lg' :
    size === 'sm'      ? 'mbds-button-sm' :
    size === 'lg'      ? 'mbds-button-lg' :
                         '';
  const variantClass = `mbds-button-${variant}`;
  return [base, sizeClass, variantClass].filter(Boolean).join(' ');
}

// ─── createButton ─────────────────────────────────────────────────────────────

export function createButton(options: ButtonOptions): HTMLButtonElement {
  const { variant = 'default', size = 'default', label, ariaLabel, disabled, type = 'button', onClick, children } = options;

  const el = document.createElement('button');
  el.type = type;
  el.className = cn(btnClass(variant, size), options.class);

  if (label) el.textContent = label;
  if (ariaLabel) el.setAttribute('aria-label', ariaLabel);
  if (options.ariaBusy) el.setAttribute('aria-busy', 'true');
  if (options.ariaInvalid) el.setAttribute('aria-invalid', 'true');
  if (disabled) el.disabled = true;

  if (children) {
    if (typeof children === 'string') {
      // PATCH: security — sanitizeHtml obrigatório em innerHTML (ver guideline 09-seguranca-xss.md)
      el.innerHTML = sanitizeHtml(children);
    } else {
      el.appendChild(children);
    }
  }

  if (onClick) el.addEventListener('click', onClick);

  return el;
}

// ─── Icons ────────────────────────────────────────────────────────────────────

import { Plus, Trash2, Pencil, ChevronRight, Download, Loader2, X } from 'lucide';

export type ButtonIconKind = 'plus' | 'trash' | 'pencil' | 'chevron-right' | 'download' | 'loader' | 'x';

type LucideIconNode = [string, Record<string, string>];

const BUTTON_ICON_MAP: Record<ButtonIconKind, LucideIconNode[]> = {
  'plus':          Plus         as unknown as LucideIconNode[],
  'trash':         Trash2       as unknown as LucideIconNode[],
  'pencil':        Pencil       as unknown as LucideIconNode[],
  'chevron-right': ChevronRight as unknown as LucideIconNode[],
  'download':      Download     as unknown as LucideIconNode[],
  'loader':        Loader2      as unknown as LucideIconNode[],
  'x':             X            as unknown as LucideIconNode[],
};

export type ButtonIconSize = 'sm' | 'md' | 'lg';

export function createButtonIcon(
  kind: ButtonIconKind,
  options: { size?: ButtonIconSize; spin?: boolean; className?: string } = {},
): SVGSVGElement {
  const { size = 'md', spin, className } = options;
  const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
  svg.setAttribute('viewBox', '0 0 24 24');
  svg.setAttribute('fill', 'none');
  svg.setAttribute('stroke', 'currentColor');
  svg.setAttribute('stroke-width', '2');
  svg.setAttribute('stroke-linecap', 'round');
  svg.setAttribute('stroke-linejoin', 'round');
  svg.setAttribute('aria-hidden', 'true');
  // Classes próprias .mbds-* — independentes de Tailwind e de cascade externa.
  // .mbds-button-icon-svg dá width/height base (1rem); modificador -<size> ajusta.
  svg.setAttribute(
    'class',
    cn('mbds-button-icon-svg', `mbds-button-icon-svg-${size}`, spin && 'mbds-spin', className),
  );

  for (const [tag, attrs] of BUTTON_ICON_MAP[kind]) {
    const child = document.createElementNS('http://www.w3.org/2000/svg', tag);
    for (const [k, v] of Object.entries(attrs)) child.setAttribute(k, v);
    svg.appendChild(child);
  }
  return svg;
}

/*
 * ─── mbds-button ───────────────────────────────────────────────────────────────
 * Componente standalone — zero dependência de Tailwind ou basecoat-css.
 * Consome apenas custom properties já definidas em tokens.css + themes/*.css.
 *
 * A11Y — WCAG 1.4.4 (Resize Text 200%):
 * Sem `height` fixo. Altura final é resultado de padding-block + line-height,
 * de modo que o button cresça proporcionalmente ao tamanho de fonte do navegador
 * (ex: zoom textual, settings → font size). NUNCA reintroduzir `height` nem
 * `min-height` em pixels fixos.
 *
 * Tokens de cor: --primary, --primary-foreground, --secondary, --secondary-foreground,
 *                --accent, --accent-foreground, --destructive, --destructive-foreground,
 *                --background, --foreground, --input, --ring, --border
 * Tokens de spacing: --spacing-* (grid 8: múltiplos/divisores de 8 apenas)
 * Tokens de raio: --radius-button
 * Tokens de tipografia: --font-family
 *
 * Variantes: default (primary), secondary, outline, ghost, link, destructive
 * Tamanhos: sm, default (padrão), lg + icon-only equivalentes
 *
 * Estados: :hover, :focus-visible, :disabled, [aria-pressed="true"], [aria-invalid="true"]
 * Dark: .dark .mbds-button-* (combina via cascade)
 */

/* ── Base (todas as variantes e tamanhos compartilham) ─────────────────────── */
.mbds-button {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-2);
  padding-inline: var(--spacing-4);
  padding-block: var(--spacing-2);
  border: 0 solid transparent;
  border-radius: var(--radius-button, 0.625rem);
  background: transparent;
  color: inherit;
  font-family: var(--font-family, inherit);
  font-size: 0.875rem;                          /* 14px — text-sm */
  line-height: 1.25;                            /* unitless — escala com font-size */
  font-weight: var(--font-weight-medium, 500);
  white-space: nowrap;
  text-decoration: none;
  cursor: pointer;
  outline: none;
  transition: background-color 150ms, color 150ms, border-color 150ms, box-shadow 150ms, opacity 150ms;
  -webkit-user-select: none;
  user-select: none;
}

/* SVG children — usam classes específicas para garantir tamanho mesmo quando
 * o componente é renderizado em contextos com cascade hostil (ex: emotion-css
 * do Storybook). Dimensões em rem (escalam com font-size do <html>) e não em
 * em (que dependeria do font-size do button, vulnerável a sobrescrita). */
.mbds-button > svg,
.mbds-button-icon-svg {
  pointer-events: none;
  flex-shrink: 0;
  width: 1rem;                                  /* 16px — default */
  height: 1rem;
}
.mbds-button-icon-svg-sm { width: 0.875rem; height: 0.875rem; } /* 14px */
.mbds-button-icon-svg-md { width: 1rem;     height: 1rem;     } /* 16px (default explícito) */
.mbds-button-icon-svg-lg { width: 1.25rem;  height: 1.25rem;  } /* 20px */

/* Quando o button tem ícone (qualquer SVG filho direto), reduz padding lateral */
.mbds-button:has(> svg) {
  padding-inline: var(--spacing-2);
}

/* ── Estados ───────────────────────────────────────────────────────────────── */
.mbds-button:focus-visible {
  box-shadow: 0 0 0 2px hsl(var(--background)), 0 0 0 5px hsl(var(--ring) / 0.5);
}
.mbds-button:disabled,
.mbds-button[aria-disabled="true"] {
  pointer-events: none;
  opacity: 0.5;
}
.mbds-button[aria-invalid="true"] {
  box-shadow: 0 0 0 2px hsl(var(--background)), 0 0 0 5px hsl(var(--destructive) / 0.4);
}

/* ── Tamanhos ──────────────────────────────────────────────────────────────────
 * Diferenciados por font-size + padding-block (não por height).
 * Texto e altura crescem juntos quando o usuário aumenta o tamanho da fonte. */
/* Escala vertical (grid 8 estrito — múltiplos/divisores de 8):
 *   sm:      padding-block 4 + 12×1.25 = ~23px
 *   default: padding-block 8 + 14×1.25 = ~33.5px
 *   lg:      padding-block 8 + 16×1.25 = ~36px
 *
 * lg diferencia de default pelo font-size (16 vs 14). sm reduz padding + font. */
.mbds-button-sm {
  gap: var(--spacing-2);
  padding-inline: var(--spacing-4);
  padding-block: var(--spacing-1);
  font-size: 0.75rem;                           /* 12px */
}
.mbds-button-sm:has(> svg) {
  padding-inline: var(--spacing-2);
}
.mbds-button-lg {
  gap: var(--spacing-2);
  padding-inline: var(--spacing-6);
  padding-block: var(--spacing-2);
  font-size: 1rem;                              /* 16px */
}
.mbds-button-lg:has(> svg) {
  padding-inline: var(--spacing-4);
}

/* Icon-only (quadrado) — sem texto. width/height explícitos em rem garantem
 * tamanho previsível em qualquer contexto (não dependem de font-size do
 * componente nem de cascade externa). Como não há texto, height fixo aqui
 * não viola a regra WCAG 1.4.4 — não existe texto a ser cortado.
 * O ícone interno escala via classes .mbds-button-icon-svg-* aplicadas pela
 * factory, independentes do font-size do botão. */
.mbds-button-icon,
.mbds-button-icon-sm,
.mbds-button-icon-lg {
  padding: 0;
}
.mbds-button-icon-sm {
  width: 2rem;                                  /* 32px */
  height: 2rem;
}
.mbds-button-icon {
  width: 2.25rem;                               /* 36px */
  height: 2.25rem;
}
.mbds-button-icon-lg {
  width: 2.5rem;                                /* 40px */
  height: 2.5rem;
}

/* ── Variantes ─────────────────────────────────────────────────────────────── */

/* Default = primary (filled) */
.mbds-button-default {
  background-color: hsl(var(--primary));
  color: hsl(var(--primary-foreground));
  box-shadow: 0 1px 2px 0 rgb(0 0 0 / 0.05);
}
.mbds-button-default:hover {
  background-color: hsl(var(--primary) / 0.9);
}
.mbds-button-default[aria-pressed="true"] {
  background-color: hsl(var(--primary) / 0.9);
}

/* Secondary */
.mbds-button-secondary {
  background-color: hsl(var(--secondary));
  color: hsl(var(--secondary-foreground));
  box-shadow: 0 1px 2px 0 rgb(0 0 0 / 0.05);
}
.mbds-button-secondary:hover,
.mbds-button-secondary[aria-pressed="true"] {
  background-color: hsl(var(--secondary) / 0.8);
}

/* Outline */
.mbds-button-outline {
  border: 1px solid hsl(var(--border));
  background-color: hsl(var(--background));
  color: hsl(var(--foreground));
  box-shadow: 0 1px 2px 0 rgb(0 0 0 / 0.05);
}
.mbds-button-outline:hover,
.mbds-button-outline[aria-pressed="true"] {
  background-color: hsl(var(--accent));
  color: hsl(var(--accent-foreground));
}
.dark .mbds-button-outline {
  border-color: hsl(var(--input));
  background-color: hsl(var(--input) / 0.3);
}
.dark .mbds-button-outline:hover,
.dark .mbds-button-outline[aria-pressed="true"] {
  background-color: hsl(var(--accent) / 0.5);
}

/* Ghost */
.mbds-button-ghost {
  color: hsl(var(--foreground));
}
.mbds-button-ghost:hover,
.mbds-button-ghost[aria-pressed="true"] {
  background-color: hsl(var(--accent));
  color: hsl(var(--accent-foreground));
}
.dark .mbds-button-ghost:hover,
.dark .mbds-button-ghost[aria-pressed="true"] {
  background-color: hsl(var(--accent) / 0.5);
}

/* Link */
.mbds-button-link {
  padding: 0;
  background: transparent;
  color: hsl(var(--primary));
  text-underline-offset: 4px;
}
.mbds-button-link:hover,
.mbds-button-link[aria-pressed="true"] {
  text-decoration: underline;
}

/* Destructive (soft style, alinhada ao restante do projeto) */
.mbds-button-destructive {
  background-color: hsl(var(--destructive) / 0.1);
  color: hsl(var(--destructive));
  box-shadow: 0 1px 2px 0 rgb(0 0 0 / 0.05);
}
.mbds-button-destructive:hover,
.mbds-button-destructive[aria-pressed="true"] {
  background-color: hsl(var(--destructive) / 0.15);
}
.mbds-button-destructive:focus-visible {
  box-shadow: 0 0 0 2px hsl(var(--background)), 0 0 0 5px hsl(var(--destructive) / 0.4);
}
.dark .mbds-button-destructive {
  background-color: hsl(var(--destructive) / 0.15);
}
.dark .mbds-button-destructive:hover {
  background-color: hsl(var(--destructive) / 0.25);
}

/* ── Spin (loading) ─────────────────────────────────────────────────────────── */
@keyframes mbds-spin {
  to { transform: rotate(360deg); }
}
.mbds-spin {
  animation: mbds-spin 1s linear infinite;
}

/* ── Animação reduzida ─────────────────────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .mbds-button {
    transition: none;
  }
  .mbds-spin {
    animation: none;
  }
}
